#include <numeric>
#include <iostream>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    TreeNode* deleteNode(TreeNode* root, int key) {
        if (!root) return root;
        if (key < root->val) {
            root->left = deleteNode(root->left, key);
        } else if (key > root->val) {
            root->right = deleteNode(root->right, key);
        } else {
            if (!root->left) {
                TreeNode* temp = root->right;
                delete root;
                return temp;
            } else if (!root->right) {
                TreeNode* temp = root->left;
                delete root;
                return temp;
            }
            TreeNode* temp = root->right;
            while (temp->left) {
                temp = temp->left;
            }
            root->val = temp->val;
            root->right = deleteNode(root->right, temp->val);
        }
        return root;
    }
};

void printTree(TreeNode* node) {
    if (node) {
        cout << node->val << endl;
        printTree(node->left);
        printTree(node->right);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    TreeNode* root = nullptr;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        if (!root) {
            root = new TreeNode(val);
        } else {
            TreeNode* node = root;
            while (true) {
                if (val < node->val) {
                    if (!node->left) {
                        node->left = new TreeNode(val);
                        break;
                    }
                    node = node->left;
                } else {
                    if (!node->right) {
                        node->right = new TreeNode(val);
                        break;
                    }
                    node = node->right;
                }
            }
        }
    }
    int key;
    cin >> key;
    Solution sol;
    root = sol.deleteNode(root, key);
    printTree(root);
    return 0;
}
